BRAND = "agntspce-search"
BRAND_LOG_PREFIX = "agntspce-search"
BRAND_ENV_PREFIX = "AGNTSPCE_SEARCH"
BRAND_DATA_DIR = "agntspce"
BRAND_CACHE_SUBDIR = "search"
BRAND_README_URL = "https://github.com/anomalyco/agntspce"


def env_var(name: str) -> str:
    return f"{BRAND_ENV_PREFIX}_{name}"


def log_prefix() -> str:
    return f"[{BRAND_LOG_PREFIX}]"


def log_msg(msg: str) -> str:
    return f"[{BRAND_LOG_PREFIX}] {msg}"
